import React, { useState, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';

const EXERCISE_LIBRARY = {
  '胸部 (Chest)': ['杠铃卧推', '上斜哑铃推举', '哑铃飞鸟', '俯卧撑', '绳索夹胸'],
  '背部 (Back)': ['引体向上', '高位下拉', '杠铃划船', '硬拉', '坐姿划船'],
  '腿部 (Legs)': ['深蹲', '腿举', '罗马尼亚硬拉', '腿屈伸', '提踵'],
  '肩部 (Shoulders)': ['杠铃推举', '哑铃侧平举', '哑铃前平举', '绳索面拉'],
  '手臂 (Arms)': ['杠铃弯举', '哑铃弯举', '三头下压', '仰卧臂屈伸'],
  '核心 (Core)': ['卷腹', '平板支撑', '悬垂举腿', '俄罗斯挺身']
};

const Stepper = ({ value, onChange, min = 0, step = 1, label }) => {
  const val = parseFloat(value) || 0;
  return (
    <div style={{display: 'flex', flexDirection: 'column', flex: 1}}>
      <span style={{fontSize: '12px', color: 'var(--apple-text-secondary)', marginBottom: '4px', textAlign: 'center'}}>{label}</span>
      <div className="stepper-input">
        <div className="stepper-btn" onClick={() => onChange(Math.max(min, val - step))}>-</div>
        <input 
          type="number" 
          value={value} 
          onChange={(e) => onChange(e.target.value)} 
          placeholder="0"
        />
        <div className="stepper-btn" onClick={() => onChange(val + step)}>+</div>
      </div>
    </div>
  );
};

const AddWorkout = () => {
  const { token } = useContext(AuthContext);
  const navigate = useNavigate();
  const [step, setStep] = useState(1); // 1: Select Exercise, 2: Log Sets

  // Form State
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [exercise, setExercise] = useState('');
  const [customExercise, setCustomExercise] = useState('');
  const [sets, setSets] = useState([{ weight: '', reps: '' }]);
  const [notes, setNotes] = useState('');

  // UI State
  const [activeCategory, setActiveCategory] = useState('胸部 (Chest)');
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);

  // V3.0 Rest Timer State
  const [timerDuration, setTimerDuration] = useState(0); // in seconds
  const [timerActive, setTimerActive] = useState(false);

  useEffect(() => {
    let interval = null;
    if (timerActive && timerDuration > 0) {
      interval = setInterval(() => {
        setTimerDuration((prev) => prev - 1);
      }, 1000);
    } else if (timerDuration <= 0 && timerActive) {
      setTimerActive(false);
      // Optional: Play a sound here or use Vibration API
      if (window.navigator && window.navigator.vibrate) {
        window.navigator.vibrate(500);
      }
    }
    return () => clearInterval(interval);
  }, [timerActive, timerDuration]);

  const startTimer = (seconds) => {
    setTimerDuration(seconds);
    setTimerActive(true);
  };

  const formatTime = (totalSeconds) => {
    const m = Math.floor(totalSeconds / 60).toString().padStart(2, '0');
    const s = (totalSeconds % 60).toString().padStart(2, '0');
    return `${m}:${s}`;
  };

  // Fetch last workout data when an exercise is selected
  const handleExerciseSelect = async (selectedEx) => {
    setExercise(selectedEx);
    setIsLoadingHistory(true);

    try {
      const res = await fetch(`${API_URL}/api/workouts/last/${encodeURIComponent(selectedEx)}`, {
        headers: { 'x-auth-token': token }
      });
      if (res.ok) {
        const lastWorkout = await res.json();
        if (lastWorkout && lastWorkout.sets && lastWorkout.sets.length > 0) {
          // Smart defaults: auto-fill with the exact sets from last time
          setSets(lastWorkout.sets.map(s => ({ weight: s.weight, reps: s.reps })));
        } else {
          // Reset if no history
          setSets([{ weight: '', reps: '' }]);
        }
      }
    } catch (err) {
      console.error('Failed to fetch history', err);
    } finally {
      setIsLoadingHistory(false);
      setStep(2);
    }
  };

  const handleSetChange = (index, field, value) => {
    const newSets = [...sets];
    newSets[index][field] = value;
    setSets(newSets);
  };

  const addSet = () => {
    setSets([...sets, { weight: '', reps: '' }]);
  };

  const removeSet = (index) => {
    if (sets.length > 1) {
      const newSets = sets.filter((_, i) => i !== index);
      setSets(newSets);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const validSets = sets.map(s => ({
      weight: parseFloat(s.weight) || 0,
      reps: parseInt(s.reps) || 0
    })).filter(s => s.weight > 0 && s.reps > 0);

    if (validSets.length === 0) {
      alert('请至少添加一组有效的训练。');
      return;
    }

    const workoutData = { date, exercise, sets: validSets, notes };

    try {
      const res = await fetch(`${API_URL}/api/workouts`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-auth-token': token,
        },
        body: JSON.stringify(workoutData),
      });
      if (res.ok) {
        navigate('/');
      } else {
        alert('添加训练失败，请重试。');
      }
    } catch (err) {
      console.error(err);
      alert('服务器错误，请稍后再试。');
    }
  };

  if (step === 1) {
    return (
      <div className="form-container" style={{maxWidth: 600, marginTop: '80px', padding: '30px'}}>
        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px'}}>
          <h2 style={{margin: 0}}>选择动作</h2>
          <button className="secondary" onClick={() => navigate('/')} style={{padding: '8px 16px', fontSize: '14px'}}>取消</button>
        </div>

        {/* Horizontal scrollable categories */}
        <div className="category-pills">
          {Object.keys(EXERCISE_LIBRARY).map(cat => (
            <div 
              key={cat} 
              className={`category-pill ${activeCategory === cat ? 'active' : ''}`}
              onClick={() => setActiveCategory(cat)}
            >
              {cat}
            </div>
          ))}
          <div 
            className={`category-pill ${activeCategory === 'Custom' ? 'active' : ''}`}
            onClick={() => setActiveCategory('Custom')}
          >
            自定义
          </div>
        </div>

        {/* Exercise List based on selection */}
        {activeCategory !== 'Custom' ? (
          <div className="exercise-list">
            {EXERCISE_LIBRARY[activeCategory].map(ex => (
              <div 
                key={ex} 
                className="exercise-option"
                onClick={() => handleExerciseSelect(ex)}
              >
                {ex}
              </div>
            ))}
          </div>
        ) : (
          <div style={{textAlign: 'left', marginTop: '20px'}}>
            <label>自定义动作名称:</label>
            <input 
              type="text" 
              placeholder="例如：保加利亚分腿蹲" 
              value={customExercise} 
              onChange={(e) => setCustomExercise(e.target.value)} 
            />
            <button 
              style={{width: '100%'}} 
              disabled={!customExercise.trim()}
              onClick={() => handleExerciseSelect(customExercise.trim())}
            >
              下一步
            </button>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="form-container" style={{maxWidth: 600, marginTop: '80px', padding: '30px'}}>
      <div style={{display: 'flex', alignItems: 'center', marginBottom: '20px'}}>
        <button 
          className="secondary" 
          onClick={() => setStep(1)} 
          style={{padding: '8px 16px', marginRight: '15px', borderRadius: '12px'}}
        >
          &larr; 返回
        </button>
        <h2 style={{margin: 0}}>{exercise}</h2>
      </div>

      <form onSubmit={handleSubmit} style={{textAlign: 'left'}}>
        <label>日期:</label>
        <input type="date" value={date} onChange={(e) => setDate(e.target.value)} required style={{marginBottom: '30px'}} />

        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px'}}>
          <label style={{margin: 0}}>组数与次数:</label>
        </div>

        {sets.map((set, index) => (
          <div key={index} className="set-row">
            <div className="set-number">{index + 1}</div>

            {/* Custom Stepper for Weight */}
            <Stepper 
              label="重量 (kg)"
              value={set.weight} 
              step={2.5}
              onChange={(val) => handleSetChange(index, 'weight', val)} 
            />

            {/* Custom Stepper for Reps */}
            <Stepper 
              label="次数"
              value={set.reps} 
              step={1}
              onChange={(val) => handleSetChange(index, 'reps', val)} 
            />

            <button type="button" className="secondary" style={{width: '40px', height: '40px', padding: 0, borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '18px'}} onClick={() => removeSet(index)}>
              &times;
            </button>
          </div>
        ))}
        <button type="button" className="secondary" style={{marginBottom: 10, width: '100%', background: 'rgba(0,113,227,0.08)', color: 'var(--apple-blue)', fontWeight: 600}} onClick={addSet}>
          + 添加一组
        </button>

        {/* V3.0 Gym Rest Timer Quick Buttons */}
        <div style={{marginBottom: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
           <span style={{fontSize: '13px', color: 'var(--apple-text-secondary)', fontWeight: 500}}>练完一组了？开始休息计时：</span>
        </div>
        <div className="quick-timer-btns">
          <button type="button" onClick={() => startTimer(60)}>1:00</button>
          <button type="button" onClick={() => startTimer(90)}>1:30</button>
          <button type="button" onClick={() => startTimer(120)}>2:00</button>
        </div>

        <label>备注 (选填):</label>
        <textarea placeholder="今天感觉如何？..." value={notes} onChange={(e) => setNotes(e.target.value)} rows="2" style={{marginBottom: '30px'}} />

        <div style={{display: 'flex', gap: '10px'}}>
          <button type="submit" style={{flex: 1, fontSize: '17px', padding: '16px'}}>保存训练</button>
        </div>
      </form>

      {/* Floating Global Timer */}
      {timerActive && (
        <div className="rest-timer-bar">
           <div className="timer-clock">⏳ {formatTime(timerDuration)}</div>
           <div className="timer-controls">
             <button type="button" onClick={() => setTimerDuration(prev => prev + 30)}>+30s</button>
             <button type="button" onClick={() => setTimerActive(false)}>结束</button>
           </div>
        </div>
      )}
    </div>
  );
};

export default AddWorkout;
